export type Cell = [number, number];

const cellKey = ([x, y]: Cell): string => `${x},${y}`;

const neighborsOf = ([x, y]: Cell): Cell[] => {
  const result: Cell[] = [];
  for (let dx = -1; dx <= 1; dx++) {
    for (let dy = -1; dy <= 1; dy++) {
      if (dx !== 0 || dy !== 0) {
        result.push([x + dx, y + dy]);
      }
    }
  }
  return result;
};

export function nextGeneration(cells: Cell[]): Cell[] {
  const liveSet = new Set(cells.map(cellKey));

  const liveNeighborCounts = new Map<string, { cell: Cell; count: number }>();
  for (const cell of cells) {
    for (const neighbor of neighborsOf(cell)) {
      const key = cellKey(neighbor);
      const entry = liveNeighborCounts.get(key) ?? { cell: neighbor, count: 0 };
      entry.count++;
      liveNeighborCounts.set(key, entry);
    }
  }

  const nextGen: Cell[] = [];
  for (const [key, { cell, count }] of liveNeighborCounts) {
    const isAlive = liveSet.has(key);
    if (count === 3 || (isAlive && count === 2)) {
      nextGen.push(cell);
    }
  }

  return nextGen;
}
